\`\`\`rust
/// Verify no heap allocation for borrowed placeholders
#[test]
fn test_no_allocation_borrowed() {
    // This test is conceptual - actual verification requires DHAT or similar

    // Get baseline allocation count (if available)
    let before = allocation_count();

    for _ in 0..10000 {
        let _: Cow<'static, str> = Cow::Borrowed(placeholders::IMAGE);
    }

    let after = allocation_count();

    // Should be zero allocations for borrowed strings
    assert_eq!(before, after, "Borrowed Cow should not allocate");
}

/// Compare allocation counts: old vs new approach
#[test]
fn test_allocation_reduction() {
    // Old approach: allocates each time
    let mut old_count = 0;
    for _ in 0..1000 {
        let s = String::from("[image]");
        old_count += s.capacity();
        std::hint::black_box(s);
    }

    // New approach: zero allocations
    let mut new_count = 0;
    for _ in 0..1000 {
        let s: Cow<'static, str> = Cow::Borrowed(placeholders::IMAGE);
        // Borrowed Cow has no owned capacity
        if let Cow::Owned(ref o) = s {
            new_count += o.capacity();
        }
        std::hint::black_box(s);
    }

    println!("Old total capacity: {} bytes", old_count);
    println!("New total capacity: {} bytes", new_count);

    assert!(new_count < old_count);
    assert_eq!(new_count, 0, "Borrowed should allocate nothing");
}
