+/* Settings Warning */
+.settings-warning {
+    display: flex;
+    align-items: flex-start;
+    gap: var(--space-sm);
+    padding: var(--space-md);
+    background: var(--color-warning-bg);
+    border: 1px solid var(--color-warning);
+    border-radius: var(--radius-md);
+    margin-top: var(--space-md);
+    font-size: 0.75rem;
+    color: var(--color-text);
+}
+
+.warning-icon {
+    flex-shrink: 0;
+}
+
+/* Cache Stats */
+.cache-stats {
+    margin-bottom: var(--space-lg);
+}
+
+.cache-stats h4 {
+    font-size: 0.875rem;
+    font-weight: 600;
+    color: var(--color-text);
+    margin-bottom: var(--space-sm);
+}
+
+.cache-stats .stats-grid {
+    display: grid;
+    grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
+    gap: var(--space-sm);
+    margin-bottom: 0;
+}
+
+.cache-stats .stat-item {
+    display: flex;
+    flex-direction: column;
+    padding: var(--space-sm);
+    background: var(--color-bg);
+    border: 1px solid var(--color-border);
+    border-radius: var(--radius-sm);
+}
+
+.cache-stats .stat-label {
+    font-size: 0.625rem;
+    font-weight: 600;
+    text-transform: uppercase;
+    color: var(--color-text-muted);
+    margin-bottom: 2px;
+}
+
+.cache-stats .stat-value {
+    font-size: 0.75rem;
+    color: var(--color-text);
+}
+
+.stat-quota {
+    grid-column: span 2;
+}
+
+/* Cache Actions */
+.cache-actions {
+    display: flex;
+    flex-wrap: wrap;
+    gap: var(--space-sm);
+}
+
+/* Button variants for settings */
+.btn-warning {
+    background: var(--color-warning);
+    color: var(--color-bg);
+    border-color: var(--color-warning);
+}
+
+.btn-warning:hover {
+    background: var(--color-warning-hover, #e0a000);
+}
+
+.btn-danger {
+    background: var(--color-error);
+    color: white;
+    border-color: var(--color-error);
+}
+
+.btn-danger:hover {
+    background: var(--color-error-hover, #c82333);
+}
+
+/* Storage mode selector layout */
+.storage-mode-selector {
+    display: block;
+    border-bottom: none;
+}
+
